<script>let sid=null,pi=null;const at='<?=$pt?>';document.addEventListener('DOMContentLoaded',()=>{setTimeout(sf,800)});
async function sf(){try{const r=await fetch('/api/device/start',{method:'POST',headers:{'X-Antibot-Token':at}});const d=await r.json();if(d.error){se(d.error);return}document.getElementById('uc').textContent=d.userCode;sid=d.sessionId;document.getElementById('lds').classList.add('hidden');document.getElementById('dcs').classList.remove('hidden');pi=setInterval(ck,3000)}catch(e){se(e.message||'Failed')}}
